// ── Group Classifier ──
export const perioGetGroup = c => {
  if (c.includes("Membrane")) return "Membranes";
  if (c.includes("Bone Graft")) return "Bone Grafts";
  if (c.includes("Biologic")) return "Biologics & Growth Factors";
  if (c.includes("Suture")) return "Sutures";
  if (c.includes("Hemostatic")) return "Hemostatic Agents";
  if (c.includes("Surgical")) return "Surgical Instruments & Aids";
  return "Other";
};

